/**
 * imgify — pi extension
 *
 * Converts a written prompt/message into an image and sends that image to the
 * chat model (which must be vision-capable to actually "see" it).
 *
 * Three ways to use it:
 *
 *  1. Prefix trigger (input transform). With the default config, typing a
 *     message that starts with "@img " converts the rest of the line into an
 *     image and attaches it to the message before the agent sees it:
 *
 *         @img Draw a cat wearing a hat
 *
 *     Set IMAGIFY_TRIGGER=always to convert every message.
 *
 *  2. Slash command. Explicitly convert a prompt and send it:
 *
 *         /imgify Explain this diagram
 *
 *  3. Tool. The LLM can call `imgify` to generate an image from a prompt and
 *     then reason about the returned image itself.
 *
 * Modes: the prompt is always rendered locally onto a PNG (no AI image model,
 * no API key). Configure colors/size via IMAGIFY_RENDER_* env vars.
 */

import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";
import { Type } from "typebox";
import { loadConfig, type ImgifyConfig } from "./config";
import { generateImage } from "./image-gen";

export default function (pi: ExtensionAPI) {
  // Config is session-scoped; reload on each session start so cwd/env updates apply.
  let config: ImgifyConfig = loadConfig(process.cwd());

  pi.on("session_start", (_event, ctx) => {
    config = loadConfig(ctx.cwd);
  });

  const visionWarning = (ctx: {
    model?: { input: ("text" | "image")[] } | undefined;
    ui: { notify: (m: string, t?: "info" | "warning" | "error") => void };
  }) => {
    const supportsVision = ctx.model?.input.includes("image");
    if (!supportsVision) {
      ctx.ui.notify(
        "imgify: active model may not support images — the image is attached anyway.",
        "warning",
      );
    }
  };

  // 1) Input transform: convert the prompt into an image and attach it to the
  //    message that gets sent to the chat model.
  pi.on("input", async (event, ctx) => {
    // Don't re-process messages we ourselves inject.
    if (event.source === "extension") return { action: "continue" };

    const triggered =
      config.trigger === "always" || event.text.startsWith(config.prefix);
    if (!triggered) return { action: "continue" };

    const prompt =
      config.trigger === "always"
        ? event.text
        : event.text.slice(config.prefix.length).trim();

    if (!prompt) {
      ctx.ui.notify(`imgify: nothing to convert after "${config.prefix}"`, "warning");
      return { action: "handled" };
    }

    visionWarning(ctx);

    try {
      const { content } = await generateImage(prompt, config, ctx.signal);
      return {
        action: "transform",
        text: `Here is an image generated from your prompt: "${prompt}"`,
        images: [content],
      };
    } catch (err) {
      ctx.ui.notify(`imgify failed: ${(err as Error).message}`, "error");
      // Fall back to sending the plain text so the user isn't blocked.
      return { action: "continue" };
    }
  });

  // 2) Slash command: convert a prompt and send the image to the chat model.
  pi.registerCommand(config.command, {
    description:
      "Convert a prompt into an image and send it to the chat model",
    handler: async (args, ctx) => {
      const prompt = args.trim();
      if (!prompt) {
        ctx.ui.notify(`Usage: /${config.command} <prompt>`, "warning");
        return;
      }
      if (!ctx.isIdle()) {
        ctx.ui.notify("Agent is busy — wait for it to finish.", "warning");
        return;
      }

      visionWarning(ctx);

      try {
        ctx.ui.setStatus("imgify", "Generating image…");
        const { content, path } = await generateImage(prompt, config, ctx.signal);
        ctx.ui.setStatus("imgify", undefined);
        if (path) ctx.ui.notify(`Image saved to ${path}`, "info");

        pi.sendUserMessage([
          {
            type: "text",
            text: `Here is an image generated from your prompt: "${prompt}"`,
          },
          content,
        ]);
      } catch (err) {
        ctx.ui.setStatus("imgify", undefined);
        ctx.ui.notify(`imgify failed: ${(err as Error).message}`, "error");
      }
    },
  });

  // 3) Tool: let the LLM generate an image and reason about it.
  pi.registerTool({
    name: "imgify",
    label: "Imgify",
    description:
      "Convert a text prompt into an image and return it so the model can see and reason about it.",
    promptSnippet: "Generate an image from a text prompt",
    promptGuidelines: [
      "Use imgify to turn a user's written prompt into an image and then reason about that image.",
    ],
    parameters: Type.Object({
      prompt: Type.String({
        description: "The prompt or text to convert into an image",
      }),
    }),
    async execute(_toolCallId, params, signal, _onUpdate, _ctx) {
      const { content, path } = await generateImage(params.prompt, config, signal);
      return {
        content: [
          {
            type: "text",
            text:
              `Generated an image from prompt: "${params.prompt}"` +
              (path ? `\nSaved to: ${path}` : ""),
          },
          content,
        ],
        details: { path: path ?? null, mimeType: content.mimeType },
      };
    },
  });
}

/**
 * imgify — image generation
 *
 * The prompt text is rendered onto a local PNG using @napi-rs/canvas. No AI
 * image model and no API key are required.
 *
 * The result is always returned as an inline base64 `ImageContent` plus the
 * path where it was also written to disk (when writable).
 */

import type { ImageContent } from "@earendil-works/pi-ai";
import { resolve as resolvePath } from "node:path";
import { mkdir, writeFile } from "node:fs/promises";
import type { ImgifyConfig } from "./config";

export interface GeneratedImage {
  content: ImageContent;
  /** Filesystem path of the saved copy, if it could be written. */
  path?: string;
}

/** Wrap text, save a PNG copy, and return inline base64 image content. */
async function saveAndWrap(
  png: Buffer,
  config: ImgifyConfig,
  baseName: string,
): Promise<GeneratedImage> {
  const content: ImageContent = {
    type: "image",
    data: png.toString("base64"),
    mimeType: "image/png",
  };

  try {
    await mkdir(config.outputDir, { recursive: true });
    const path = resolvePath(config.outputDir, `${baseName}-${Date.now()}.png`);
    await writeFile(path, png);
    return { content, path };
  } catch {
    // Saving to disk is best-effort; the inline image is what matters.
    return { content };
  }
}

function wrapText(
  measure: (text: string) => number,
  text: string,
  maxWidth: number,
): string[] {
  const lines: string[] = [];
  let line = "";
  for (const word of text.split(/\s+/)) {
    const candidate = line ? `${line} ${word}` : word;
    if (line && measure(candidate) > maxWidth) {
      lines.push(line);
      line = word;
    } else {
      line = candidate;
    }
  }
  if (line) lines.push(line);
  return lines.length ? lines : [""];
}

/** Pick a usable sans-serif font family via @napi-rs/canvas fontconfig support. */
function resolveFontFamily(
  explicit: string | undefined,
  GlobalFonts: typeof import("@napi-rs/canvas")["GlobalFonts"],
): string {
  if (explicit) return explicit;
  // Index system fonts so family names resolve when used in ctx.font.
  GlobalFonts.loadSystemFonts();
  const families = GlobalFonts.getFamilies();
  const preferred =
    families.find((f) => /noto sans|dejavu|liberation|arial|sans/i.test(f)) ??
    families[0];
  return preferred ?? "sans-serif";
}

/** Render the prompt text onto a PNG image. */
export async function renderTextToImage(
  text: string,
  config: ImgifyConfig,
  _signal?: AbortSignal,
): Promise<GeneratedImage> {
  const { createCanvas, GlobalFonts } = await import("@napi-rs/canvas");
  const { render } = config;

  const family = resolveFontFamily(render.fontFamily, GlobalFonts);
  const font = `${render.fontSize}px ${family}`;

  // First pass: measure to compute the required canvas height.
  const measuring = createCanvas(render.maxWidth, 10);
  const mctx = measuring.getContext("2d");
  mctx.font = font;
  const lines = wrapText(
    (t) => mctx.measureText(t).width,
    text,
    render.maxWidth - render.padding * 2,
  );

  const lineHeight = Math.round(render.fontSize * 1.4);
  const height = render.padding * 2 + lines.length * lineHeight;

  const canvas = createCanvas(render.maxWidth, height);
  const ctx = canvas.getContext("2d");
  ctx.fillStyle = render.background;
  ctx.fillRect(0, 0, render.maxWidth, height);
  ctx.fillStyle = render.foreground;
  ctx.font = font;
  ctx.textBaseline = "top";
  lines.forEach((line, i) => {
    ctx.fillText(line, render.padding, render.padding + i * lineHeight);
  });

  const png = canvas.toBuffer("image/png");
  return saveAndWrap(png, config, "render");
}

/** Convert a prompt into an image (locally rendered text). */
export async function generateImage(
  prompt: string,
  config: ImgifyConfig,
  signal?: AbortSignal,
): Promise<GeneratedImage> {
  return renderTextToImage(prompt, config, signal);
}

/**
 * imgify — configuration
 *
 * Reads config from environment variables so the plugin can be tuned without
 * editing code. All values fall back to sensible defaults.
 *
 * Image generation is done locally (the prompt text is rendered onto a PNG via
 * @napi-rs/canvas) — no AI image model and no API key required.
 */

export type ImgifyTrigger = "prefix" | "always";

export interface ImgifyConfig {
  /** When to convert. "prefix" only converts messages starting with `prefix`. */
  trigger: ImgifyTrigger;
  /** Prefix that triggers conversion in "prefix" mode. */
  prefix: string;
  /** Slash command name. */
  command: string;
  /** Directory where generated images are also written to disk. */
  outputDir: string;
  /** Options for local text rendering. */
  render: {
    background: string;
    foreground: string;
    fontSize: number;
    padding: number;
    maxWidth: number;
    /** Optional explicit font family; auto-detected if omitted. */
    fontFamily?: string;
  };
}

export function loadConfig(cwd: string): ImgifyConfig {
  const env = process.env;

  return {
    trigger: (env.IMAGIFY_TRIGGER ?? "prefix") as ImgifyTrigger,
    prefix: env.IMAGIFY_PREFIX ?? "imgify ",
    command: env.IMAGIFY_COMMAND ?? "imgify",
    outputDir: env.IMAGIFY_OUTPUT_DIR
      ? env.IMAGIFY_OUTPUT_DIR
      : `${cwd}/.imgify`,

    render: {
      background: env.IMAGIFY_RENDER_BG ?? "#0d1117",
      foreground: env.IMAGIFY_RENDER_FG ?? "#e6edf3",
      fontSize: env.IMAGIFY_RENDER_FONT_SIZE
        ? Number(env.IMAGIFY_RENDER_FONT_SIZE)
        : 36,
      padding: env.IMAGIFY_RENDER_PADDING
        ? Number(env.IMAGIFY_RENDER_PADDING)
        : 40,
      maxWidth: env.IMAGIFY_RENDER_MAX_WIDTH
        ? Number(env.IMAGIFY_RENDER_MAX_WIDTH)
        : 900,
      fontFamily: env.IMAGIFY_RENDER_FONT_FAMILY || undefined,
    },
  };
}

